# Find where kn block ends and insert before closing brace
text = open('translations.js').read()
# Find kn block closing
import re
kn_pos = text.index('\n  kn: {')
# Find the closing of kn: search for '\n  },' after kn_pos but within reasonable range
search_from = kn_pos + 10
close_pos = text.find('\n  },\n\n  /* ─── TAMIL', search_from)
if close_pos == -1:
    # Try alternate
    close_pos = text.find('\n  },\n\n  /* ─── TAMIL', search_from)
print(f"Close found at: {close_pos}")
print(f"Context: {repr(text[close_pos:close_pos+40])}")

# Insert before the closing brace+comma
new_text = text[:close_pos] + '\n' + EXTRA + text[close_pos:]
open('translations.js', 'w').write(new_text)
print(f"Done. File: {len(text)} -> {len(new_text)} chars")
